using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyTypeEditor : UITypeEditor
{
    public override object? EditValue(
        ITypeDescriptorContext? context,
        IServiceProvider provider,
        object? value)
    {
        var editorService = provider?.GetService(typeof(IWindowsFormsEditorService))
            as IWindowsFormsEditorService;
        if (editorService is null)
            return value;

        // .NET 9: DropDownControl now throws ArgumentNullException when
        // passed null. Guard against null before calling.
        var control = CreateEditorControl(value);
        if (control is not null)
        {
            editorService.DropDownControl(control);
            value = control.Tag;
        }

        return value;
    }

    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    private static Control? CreateEditorControl(object? currentValue)
    {
        if (currentValue is null)
            return null;

        var listBox = new ListBox();
        listBox.Items.Add(currentValue);
        listBox.Tag = currentValue;
        return listBox;
    }
}

